const body = $input.first().json.body || $input.first().json;
const { route, payload, source } = body;

// Route table — maps route slugs to workflow IDs
const routeTable = {
  'tg-lead-score': 'TG-07-lead-scoring',
  'tg-welcome': 'TG-08-welcome-series',
  'tg-review-request': 'TG-18-post-job-review-request',
  'tg-nps': 'TG-60-nps-survey',
  'tg-loyalty': 'TG-61-loyalty-points',
  'tg-booking': 'TG-77-ai-booking-sync',
  'tg-generate-meta': 'TG-54-ai-meta-generator',
  'tg-ai-quote': 'TG-75-ai-quoting'
};

const targetWorkflow = routeTable[route];
if (!targetWorkflow) {
  return [{ json: { error: 'Unknown route: ' + route, valid_routes: Object.keys(routeTable) } }];
}

return [{ json: { route, target: targetWorkflow, payload: payload || {}, source: source || 'api', routed_at: new Date().toISOString() } }];
